
import { Vue, Component, Prop } from "vue-property-decorator";
import LoadingSpinner from "@/components/Reusable/LoadingSpinner.vue";
import Dialog from "@/components/UI/Dialog.vue";
import DesignLibraryPassword from "@/components/Add/library/DesignLibraryPassword.vue";
import { DesignLibraryData, DesignProvider } from "@/types/design-library";
import Icon from "@/components/UI/Icon.vue";
import { logEvent } from "@/util/tracking";
import { sprintf, _doc, __, i18nFormatList } from "@/lib/i18n";
import lodash from "lodash";

@Component({
  components: { Icon, DesignLibraryPassword, Dialog, LoadingSpinner }
})
export default class DesignLibraryConfirmImportDialog extends Vue {
  @Prop()
  provider?: DesignProvider;

  @Prop()
  providerData?: DesignLibraryData;

  @Prop({ default: false })
  loading!: boolean;

  @Prop({ default: false })
  showPasswordForm!: boolean;

  importProvider() {
    logEvent("Design Library", {
      action: "provider_imported",
      provider: this.provider?.name
    });
    this.$emit("import");
  }

  get isGlobalSettingsEnabled() {
    return this.providerData?.isGlobalSettingsEnabled;
  }

  get isDesignPresetsEnabled() {
    return this.providerData?.isDesignPresetsEnabled;
  }

  get isVariablesEnabled() {
    return this.providerData?.isVariablesEnabled;
  }

  get isOxySelectorsEnabled() {
    return this.providerData?.isOxySelectorsEnabled;
  }

  get isPopupsEnabled() {
    return this.providerData?.isPopupsEnabled;
  }

  get itemsToTrash() {
    const items = [];
    items.push(__("Templates"));
    items.push(__("Headers"));
    items.push(__("Footers"));
    items.push(this.$bdox("global_blocks"));
    if (this.isPopupsEnabled) items.push(__("Popups"));

    // Escape HTML in items to prevent XSS, then wrap in safe styling tags
    const formattedItems = items.map(item => `<b>${lodash.escape(item)}</b>`);
    return i18nFormatList(formattedItems);
  }
}
